<template><div class="workspace-page"><section class="page-intro"><div><p>统一健康事件</p><h2>健康时间线</h2><span>机构自动归档的体检报告和本人日常测量按时间统一展示。</span></div></section><el-card shadow="never" v-loading="loading"><el-timeline v-if="items.length"><el-timeline-item v-for="event in items" :key="`${event.type}-${event.occurred_at}-${event.item?.id}`" :timestamp="format(event.occurred_at)" :type="event.type==='institution_report'?'success':event.type==='report_withdrawn'?'danger':'primary'"><h3>{{ event.title }}</h3><el-button v-if="event.type==='institution_report'" link type="primary" @click="router.push({name:'report-detail',params:{id:event.item.id}})">查看标准化指标</el-button></el-timeline-item></el-timeline><el-empty v-else description="暂无时间线事件"/></el-card></div></template>
<script setup>import{onMounted,ref}from"vue";import{useRouter}from"vue-router";import{fetchTimeline}from"../api/health";const router=useRouter(),loading=ref(false),items=ref([]);const format=v=>new Date(v).toLocaleString("zh-CN",{hour12:false});onMounted(async()=>{loading.value=true;try{items.value=(await fetchTimeline()).data.items||[]}finally{loading.value=false}});</script>
